import{_ as t,o as r,c as s,a9 as e}from"./chunks/framework.D4xYp1Zt.js";const i="/images/american-presidents-washington-lincoln/thirds1.png",a="/images/american-presidents-washington-lincoln/PartyVotes-Presidents-1024x468.png",o="/images/american-presidents-washington-lincoln/Mustache1-1024x127.png",l="/images/american-presidents-washington-lincoln/squares2.png",p="/images/american-presidents-washington-lincoln/washington-272x300.png",g="/images/american-presidents-washington-lincoln/adams-2-293x300.png",h="/images/american-presidents-washington-lincoln/jefferson-300x265.png",c="/images/american-presidents-washington-lincoln/National-atlas-1970-1810-loupurchase-1.png",m="/images/american-presidents-washington-lincoln/a-hamilton-national-portrait-gallery-213x300.jpg",u="/images/american-presidents-washington-lincoln/madison-300x275.png",d="/images/american-presidents-washington-lincoln/pinit_fg_en_rect_gray_20.png",A=JSON.parse('{"title":"The American Presidents—Washington to Lincoln","description":"","frontmatter":{"title":"The American Presidents—Washington to Lincoln","titleZh":"美国总统:从华盛顿到林肯","date":"2014-02-19T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html","slug":"american-presidents-washington-lincoln"},"headers":[],"relativePath":"posts/american-presidents-washington-lincoln.md","filePath":"posts/american-presidents-washington-lincoln.md","lastUpdated":1782886257000}'),w={name:"posts/american-presidents-washington-lincoln.md"};function _(f,n,b,y,k,P){return r(),s("div",null,[...n[0]||(n[0]=[e('<h1 id="美国总统-从华盛顿到林肯-·-the-american-presidents—washington-to-lincoln" tabindex="-1">美国总统:从华盛顿到林肯 · The American Presidents—Washington to Lincoln <a class="header-anchor" href="#美国总统-从华盛顿到林肯-·-the-american-presidents—washington-to-lincoln" aria-label="Permalink to &quot;美国总统:从华盛顿到林肯 · The American Presidents—Washington to Lincoln&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html</a> · 2014-02-19</p></blockquote><p>总统日 (President&#39;s Day) 是那种诡异的美国节日之一——没人搞得清它到底为啥存在、到底是啥,但反正是个假期,所以也没人问太多问题。</p><p>这个节日算是庆祝华盛顿的生日 (2 月 22 日),又算是同时庆祝华盛顿和林肯的生日 (2 月 22 日和 12 日),又算是把所有 43 位总统一锅端一起庆祝。</p><p>不管怎么说,这似乎是个花 60 个小时研究总统、然后发一篇 7000 字、迟到 30 个小时的博文的完美时机——深入挖一挖每一位美国总统究竟是何许人也、究竟干了些什么。(向所有非美国读者致歉——你们没做错任何事却要遭这个罪。)</p><p>在决定从哪开始下手时,我看了看整条总统时间线,结果发现美国的历史正好干净利落地分成三个等长的部分,每部分 75 年:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/thirds1.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="thirds"></a></p><p>我最终想把 43 位美国总统全部过一遍,但今天,从美国历史第一个、也是最动荡的那一段开始,是再合适不过了——这一段的两头正好是两位「寿星」华盛顿和林肯,而在这段时期里,这个国家的边界、法律、原则和民族认同都还在成形。我们就叫它「塑造国家的时代」吧。这个时代,每一届新政府都在设立重大先例,让下文要讲的这 16 位总统能以今天任何人都不再有机会做到的深度去塑造这个国家。</p><p>下面这张图展示了每一次选举的结果以及各政党随时间的更迭,进一步说明了华盛顿-林肯时期比美国历史其他时期要混乱得多:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/PartyVotes-Presidents.png" target="_blank" rel="noreferrer"><img src="'+a+'" alt="PartyVotes-Presidents"></a></strong></p><p>在开始之前,先说八个我在研究过程中冒出来的一般性想法:</p><p><strong>1) 43 位总统中有 17 位,也就是 40%,都叫 John、James、George 或 William。</strong></p><p><strong>2) 存在一个「胡子时代」。</strong> 1869 到 1913 年这 44 年间共有 9 位总统,<em>其中 8 位都留胡子:</em></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/Mustache1.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="Mustache"></a></p><p>而在这个时代之前和之后,<em>没有任何一位</em>其他总统留过胡子。</p><p><strong>3) 1841 到 1877 年间出现了一连串荒唐的糟糕总统。</strong></p><p>我管这叫「烂总统马戏团」,今天我们会讲到其中大部分。下面这张图展示了这段时期有多么惨烈。每个方格代表一届总统,按顺序排(所以华盛顿在最左边,奥巴马在最右边)。红色方格代表排名*垫底的 10 位总统:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/squares2.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="squares"></a></p><p>从威廉·亨利·哈里森 (William Henry Harrison) 开始,到尤利西斯·S·格兰特 (Ulysses S. Grant) 结束,「烂总统马戏团」是连续十任总统的时期,其中<em>八位排在史上最烂十位总统里</em>。一段黑暗岁月。 ** 4) 让我觉得离谱的是,几乎每一位最著名的总统,都至少有一位父母根本不知道自己的儿子后来干出了什么大事。**</p><p>乔治·华盛顿 (George Washington) 的父亲在他 11 岁时去世。想象一下,你死了,却永远不知道自己的儿子就是<em>那位伟大的乔治·华盛顿</em>。</p><p>托马斯·杰斐逊 (Thomas Jefferson) 的父亲在他 14 岁时去世。</p><p>安德鲁·杰克逊 (Andrew Jackson) 的父亲在他还是婴儿时就去世了,母亲在他 14 岁时去世。</p><p>亚伯拉罕·林肯 (Abraham Lincoln) 的母亲在他 9 岁时去世。</p><p>事实证明,这更像是常态而非例外——最近的 10 位总统里,只有肯尼迪 (JFK) 和小布什 (George W. Bush) 的父母双方都知道自己养出了一位美国总统。这个概念让我震惊。</p><p><strong>5) 总统的「临终遗言」是一种很滑稽的现象。</strong> 只要有记载,我都把下面这些总统的遗言收录了进来。这些话大多诗意宏大,显然是提前策划过、仔细斟酌过的。有意思的是,想象一位总统躺在临终病榻上,家人围绕四周,而他脑子里全部的注意力都集中在——什么时候说出那句关键的「遗言」上。要是说得太早,那他之后就得一句话都不能再讲,要是有人问他问题或者他又多活了几天,那可就尴尬了(杰斐逊可能就遇到了这种情况,你等下就会看到)。要是等得太久,他还没说出正确的遗言就死了。这些拼命想要塑造自己历史遗产的人,连临死前都得面对这最后一个难题。</p><p>再说几点专门针对前 16 位总统的想法:</p><p><strong>6) 那时候的人对「死亡」这件事简直着迷。</strong> 了解了这 16 位总统、他们的家人、朋友和同代人后,你会震惊地发现——仅仅 200 年前的美国,死亡是多么容易的一件事。孩子活过 5 岁的概率似乎不超过 50%,而一个成年人一旦过了 50 岁,感个冒或者吃了坏掉的食物,完全可能让你 5 天后就没了。在那个年代,悲剧是生活中远比现在更醒目的一部分。</p><p><strong>7) 书籍就是一切。</strong> 这些早期总统中的许多人,他们那扎实教育的一部分甚至大部分,都来自于自己读书。这提醒了我们,量产书籍这项发明在当时是多么具有开创性。在此之前,想学点什么,唯一的办法就是让某个真人当面讲给你听。而书籍让一个求知若渴的学习者(这 16 位几乎全都是这类人)得以将主动权掌握在自己手中,吸收成千上万他人脑袋里的思想和知识。反过来看,它也让像亚伯拉罕·林肯这样的人得以出版林肯-道格拉斯辩论集,把自己关于奴隶制的想法传达给全国数以万计的人,仿佛每本书都是他的一个迷你分身,让他突然之间可以同时无处不在。</p><p><strong>8) 这个国家前三分之一历史的故事,基本可以用一句话概括:</strong></p><p><em>美国领土的激进(且充满争议的)扩张,加剧了这个国家最紧绷、最具分裂性的辩论——奴隶制——因为它把「新领土是否有权自行决定是否允许奴隶制」这个问题摆到了台面上,凸显出州权终结于何处、联邦权力始于何处的模糊地带,加速把这个国家推向了内战。</em></p><p>当然,当时也有关于国家银行和关税的辩论,有关于如何对待原住民、如何跟欧洲打交道的争论,但这 16 位总统面对的<em>大多数</em>重大议题,都能被塞进上面那句斜体字里。</p><p><strong>*关于排名的说明:</strong> 上面图表和下面每幅肖像下方使用的总统排名,取自<a href="https://en.wikipedia.org/wiki/Historical_rankings_of_United_States_Presidents" target="_blank" rel="noreferrer">这里</a>,它综合平均了一大批横跨不同时期、覆盖政治光谱的民调结果。</p><p>那我们开始吧——</p><p><strong>1) 乔治·华盛顿 (George Washington)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/washington.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="washington"></a></p><p><strong>任期:</strong> 1789 – 1797 <strong>生卒:</strong> 1732 – 1799 <strong>排名:</strong> 3/43</p><p><strong>是否蓄奴?</strong> 是。</p><p><strong>他是个什么人:</strong> 硬汉中的硬汉。没念过高中,没念过大学,也没念过法学院,就一身男子汉的审慎和智慧。他在法印战争 (French and Indian War) 中是关键军官,在独立战争中是首席将军,是唯一一个大家都信得过、能负责任地担任首任总统的人。这份信任是有道理的——赢得独立战争后,他辞去了总司令一职而不是趁机夺权;担任总统后,他刻意避免表现得像国王或独裁者,自我约束只做两届,并以和平的权力交接方式卸任——为这个国家的未来立下了这些关键先例。他是那种美国人不允许说任何坏话的人物之一。</p><p>**他的总统任期:**总体上是一段和平的日子,尽管他不得不应付亚历山大·汉密尔顿 (Alexander Hamilton) 和托马斯·杰斐逊 (Thomas Jefferson) 这两位核心内阁成员——他们俩因政见不合,整个任期都在互相闹脾气。在他的告别演说中,他警告人们要提防党派之争的邪恶,以及卷入外国战争的危险——美国人牢记了这些话,直到今天,我们仍然是一个不搞党派之争、从不卷入不必要海外战争的国家。</p><p><strong>他可以吹嘘的事情:</strong></p><ul><li>第一任总统</li><li>绰号「国父」(The Father of Our Country)——这绰号挺有意思</li><li>选定华盛顿特区作为国家首都所在地</li><li>唯一一位以 100% 选举人票当选的总统</li><li>有一天,吉米·卡特 (Jimmy Carter) 决定给华盛顿追授「六星上将」军衔,所以他现在是美国历史上军衔最高的军官</li><li>出现在 25 美分硬币、1 美元纸币和拉什莫尔山 (Mount Rushmore) 上</li><li>有九万亿样东西以他的名字命名,包括他是唯一一位有一个州以他名字命名的总统</li><li>全弗吉尼亚最大的威士忌蒸馏商</li></ul><p><strong>他希望我们别记得的事情:</strong></p><ul><li>他一辈子都拥有奴隶,他去世时庄园里有 300 多名奴隶。他在死后让所有奴隶都获得了自由——但一分钟都不肯提前。</li></ul><p><strong>让他恼火的事情:</strong></p><ul><li>上任时牙齿都掉光了</li><li>他那位专横的、反对独立革命的妈</li></ul><p><strong>其他值得一提的事实:</strong></p><ul><li>他显然有相当骚气的一面——舞跳得棒,搞室内装饰,还是个热情的时尚达人。</li><li>玛莎·华盛顿 (Martha Washington) 身高 5 英尺整,而他有 6 英尺 3 英寸。</li><li>他的第一次就职演说只有 183 个词,持续了 90 秒。第二次更短。</li><li>他基本上很脏,讨厌洗澡。</li><li>他的年薪是 25,000 美元,相当于今天的 50 多万美元,其中 7% 花在了酒上。</li><li>他不跟任何人握手,因为他觉得握手有失总统身份,而是鞠躬(十年后杰斐逊废除了这一传统)。</li><li>他去世时,庄园价值 100 万美元,相当于今天的 1,900 万美元。</li></ul><p><strong>遗言:</strong>「一切安好。」华盛顿太酷了,才不在乎什么遗言。</p><p><strong>2) 约翰·亚当斯 (John Adams)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/adams-2.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="John Adams"></a></p><p>**任期:**1797 – 1801 **生卒:**1735 – 1826 **排名:**12/43</p><p>**是否拥有奴隶?**没有。</p><p>**他的情况:**一个矮胖、受过高等教育的知识分子,他的政府哲学在国家的立国政策中发挥了关键作用。他 1779 年起草的马萨诸塞州宪法为后来的美国宪法提供了大量思想和结构,他还是《独立宣言》起草委员会的成员(而且他本来是被选中执笔的那个人,后来把这个荣誉让给了托马斯·杰斐逊 (Thomas Jefferson))。他也是提名乔治·华盛顿 (George Washington) 担任总司令、以及提名约翰·马歇尔 (John Marshall) 担任最高法院首席大法官的那个人,这两个决定后来都被证明是神来之笔。</p><p>他的主要问题是,他不属于那群酷小孩。大部分国父都是安静、有威严的南方人,他们不怎么喜欢或接纳亚当斯,也不会邀请他去参加生日派对。他一辈子都因此耿耿于怀,而这确实很重要——如果他有一个更大的权贵朋友圈(华盛顿算一个,但他任期一结束就去世了),他当总统时可能会得到更多支持,做成更多事,连任第二届,今天出现在拉什莫尔山和 10 美元钞票上。</p><p>**他的总统任期:**亚当斯的总统任期取得了一些成就,比如在很多人都催他开战的情况下阻止了与法国的战争,但他在任期内大部分时间都被汉密尔顿 (Hamilton) 和杰斐逊从两党的过道两边对着脸吼。他既得不到民主共和党的支持,也得不到自己所在的联邦党的支持,一届之后就被赶下台(和他儿子一起,成为国家头 50 年里仅有的两位一届总统)。</p><p><strong>他可以吹嘘的事:</strong></p><ul><li>第一任副总统</li><li>第一位入住白宫的总统</li><li>早在反对奴隶制变成主流之前就反对奴隶制。是内战前极少数公开反对的总统之一。</li><li>创建了海军</li><li>发明了 7 月 4 日放烟花的传统</li><li>会说七种语言</li></ul><p><strong>他希望我们别记得的事:</strong></p><ul><li>他通过了《客籍法与惩治叛乱法》(Alien and Sedition Acts),禁止人们批评联邦政府,就因为大家都在冲他吼,他心里难过(他离任后第二年这法就被废除了)</li></ul><p><strong>他觉得心烦的事:</strong></p><ul><li>得接乔治·华盛顿的班——偏偏是他妈的乔治·华盛顿</li><li>作为第二任总统,竟然没能出现在拉什莫尔山上,也没有出现在任何硬币或钞票上</li><li>他的总统绰号「圆滚滚阁下」(His Rotundity),嘲笑他又矮又胖</li></ul><p><strong>其他值得一提的事:</strong></p><ul><li>他和托马斯·杰斐逊在卸任后建立了长达数十年的笔友关系,两人于同一天去世,1826 年 7 月 4 日——国家成立 50 周年纪念日。</li></ul><p><strong>遗言:</strong>「托马斯·杰斐逊还活着。」临终遗言里提到另一位总统,有点尴尬。</p><p><strong>3) 托马斯·杰斐逊 (Thomas Jefferson)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/jefferson.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="jefferson"></a></p><p><strong>任期:</strong> 1801 – 1809 <strong>在世:</strong> 1743 – 1826 <strong>排名:</strong> 4/43</p><p><strong>蓄奴者?</strong> 废话。</p><p><strong>他的故事:</strong> 一位有威严、备受尊敬、可能还有点混蛋的弗吉尼亚精英,杰斐逊学识极其渊博,基本上什么都懂什么都会——除了政治成就外,他会说四种语言,研究过动物学、建筑学、植物学、宗教、法律、历史、文学和小提琴,还发明了旋转椅和折叠梯。杰斐逊是这个新国家的主要设计师之一,并创立了一整套治国哲学,被麦迪逊、门罗等后继者所遵循。</p><p><strong>他的总统任期:</strong> 他做了一些大事,大多数是在第一任期,比如主持通过了禁止进口奴隶的法律(但国内拥有和交易奴隶仍然可以),以及派刘易斯和克拉克去探索西部。但他最大的成就是通过路易斯安那购地案,以 1500 万美元(相当于今天的 2.34 亿美元,即每英亩 42 美分)从拿破仑的法国手中买下了整个国家的中部:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/National-atlas-1970-1810-loupurchase-1.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="National-atlas-1970-1810-loupurchase-1"></a></p><p><strong>他可以吹嘘的事:</strong></p><ul><li>30 岁出头就起草了《独立宣言》,而我们中有些人在这个年纪只能在博客上画些丑陋的火柴人</li><li>出现在 5 美分硬币和总统山上</li><li>创办了弗吉尼亚大学</li></ul><p><strong>他希望我们忘掉的事:</strong></p><ul><li>他痴迷于拥有数百名奴隶,还从来不释放他们</li><li>他把自己的奴隶莎莉·海明斯搞怀孕了,而她其实是 3/4 的白人血统,还是他妻子同父异母的妹妹(他妻子的父亲和自己的奴隶生了六个孩子,莎莉就是其中一个)</li></ul><p><strong>他懊恼的事:</strong></p><ul><li>他妻子说:“求你以后我死了别再娶了”,然后下一秒就死了。杰斐逊当时才 39 岁,就因为这句话接下来 44 年都没有妻子,超级烦人。尤其是因为他这位虚伪的妻子嫁给他时自己就是个寡妇。</li><li>在娶妻之前,他向一位叫丽贝卡·伯韦尔的女人求婚,被拒绝了</li><li>他起草完《独立宣言》后,文件被送到国会审议,国会对其做了大幅改动,砍掉了四分之一的内容,用杰斐逊的话说,把他写的东西给“弄残”了</li><li>约翰·亚当斯自认为他和杰斐逊是最好的朋友,晚年给杰斐逊写了 1000 封信,杰斐逊还得一一回复</li><li>被印在了 2 美元纸币上——那种唯一没能流行起来的小面额纸币</li></ul><p><strong>其他值得一提的事实:</strong></p><ul><li>他曾是华盛顿的国务卿,但因为华盛顿总是站在他的对头亚历山大·汉密尔顿 (Alexander Hamilton) 一边,愤而辞职。华盛顿从此再没原谅过杰斐逊,也再没跟他说过一句话。</li><li>他讨厌演讲,当了八年总统只发表过两次演讲——两次就职演说</li><li>杰斐逊在欧洲游历时接触到各种欧洲美食,把他最爱的那些带回了美国,把冰淇淋、华夫饼、通心粉起司和薯条介绍给了美国人。</li><li>他养的宠物数量诡异得离谱。2 只狗、8 只鸟、9 匹马,还有 2 只活的灰熊——那是路易斯和克拉克 (Louis and Clark) 探险时(不知怎么地)给他带回来的。</li></ul><p><strong>临终遗言:</strong>「已经是四号了吗?」这不在他的计划里。几小时前他就说过他想要的临终遗言:</p><p><em>我已经为我的国家、为全人类,尽了我所能做的一切,现在,我毫无畏惧地把我的灵魂交给上帝——把我的女儿交给我的国家。</em></p><p>但他没按剧本死掉,反而又醒了一次,忘了自己不该再开口,问了句今天几号。然后他死了,于是他的临终遗言就永远变成了「已经是四号了吗?」</p><p><strong>4) 亚历山大·汉密尔顿 (Alexander Hamilton)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/a-hamilton-national-portrait-gallery.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt="a-hamilton-national-portrait-gallery"></a></p><p>不对不对,他压根不是总统,别再以为他是了。</p><p><strong>4) 詹姆斯·麦迪逊 (James Madison)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/02/madison.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="madison"></a></p><p><strong>任期:</strong> 1809 – 1816 <strong>在世:</strong> 1751 – 1836 <strong>排名:</strong> 13/43</p><p><strong>是否蓄奴?</strong> 是。拥有数百名奴隶。</p><p><strong>他的故事:</strong> 身高 5 英尺 4 英寸、体重 100 磅,萌得可爱的麦迪逊是我们的小精灵总统。他最了不起的成就其实发生在总统任期之前——他被视为《宪法》和《权利法案》起草背后最有影响力的思想家,因此得到了「宪法之父」的绰号。他还是《联邦党人文集》(<em>The Federalist Papers</em>) 的三位作者之一,这一系列文章为新宪法的批准争取了支持。</p><p><strong>他的总统任期:</strong> 上任之初他延续着托马斯·杰斐逊的政策,但很快就被拖进了那场丑陋的 1812 年战争,和英国干上了,美国输了(这一点看法不一,不少评论者提出 1812 年战争其实是打平的。这取决于你是否认为美国当时其实想偷偷拿下加拿大——如果是的话,他们就是输了)。</p><p><strong>他可以吹嘘的事:</strong></p><ul><li>成年男子体重不到 100 磅,简直是不可思议的壮举</li><li>曾任托马斯·杰斐逊的国务卿,并且是真正谈成路易斯安那购地案 (Louisiana Purchase) 的那个人</li><li>根据我的调查,他是第一位穿长裤的总统。至于前三位穿的是啥,那就不清楚了。</li></ul><p><strong>他希望我们不要记得的事:</strong></p><ul><li>卸任总统后,晚年的他变得痴迷于自己的历史遗产,偏执到会篡改自己写过的信件以及别人写给他的信</li></ul><p><strong>让他恼火的事情:</strong></p><ul><li>他是唯一一位在任期间被人从白宫里赶出去、又在战争中挨过枪子儿的总统(两件事都是拜英国人所赐,发生在 1812 年战争期间)</li></ul><p><strong>其他值得一提的事情:</strong></p><ul><li>《星条旗永不落》(The Star Spangled Banner) 是在他任内写成的</li></ul><p><strong>临终遗言:</strong> &quot;没什么,亲爱的,只是脑子里转了个念头。我躺着说话总是更利索些。&quot;(回答侄女问他怎么了)</p><p><a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html/2" target="_blank" rel="noreferrer">第 2 页(门罗到泰勒)→</a></p><p><a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html/3" target="_blank" rel="noreferrer">第 3 页(波尔克到林肯)→</a></p><p>页码:1 <a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html/2" target="_blank" rel="noreferrer">2</a> <a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html/3" target="_blank" rel="noreferrer">3</a></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html&amp;description=The%20American%20Presidents%E2%80%94Washington%20to%20Lincoln" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p>',105)])])}const x=t(w,[["render",_]]);export{A as __pageData,x as default};
